SELECT COUNT(*)
FROM woorido.challenge_members
WHERE challenge_id = #{challengeId}
  AND user_id = #{userId}
  AND privilege_status != 'LEFT'

SELECT COUNT(*) FROM woorido.challenges c WHERE c.is_public = 'Y'
AND c.status IN ('RECRUITING', 'IN_PROGRESS')
AND c.status IN ('COMPLETED', 'DISSOLVED')
AND c.status = #{status}
AND c.category = #{category}

SELECT COUNT(*)
FROM woorido.challenge_members
WHERE challenge_id = #{challengeId}
  AND user_id = #{userId}
  AND role = 'LEADER'
